import{_ as t,o as a,c as e,ag as r}from"./chunks/framework.CxZWPeXl.js";const u=JSON.parse('{"title":"提示詞管理","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/admin-prompts.md","filePath":"zh-TW/admin-prompts.md"}'),l={name:"zh-TW/admin-prompts.md"};function i(n,o,s,c,d,h){return a(),e("div",null,[...o[0]||(o[0]=[r('<h1 id="提示詞管理" tabindex="-1">提示詞管理 <a class="header-anchor" href="#提示詞管理" aria-label="Permalink to &quot;提示詞管理&quot;">​</a></h1><blockquote><p>控制 AI 的核心行為，設定其思維模式與評分標準。</p></blockquote><h2 id="概覽" tabindex="-1">概覽 <a class="header-anchor" href="#概覽" aria-label="Permalink to &quot;概覽&quot;">​</a></h2><p>提示詞 (Prompts) 是驅動整個 AI Coach 平台的核心指令。這項功能允許管理員調整 AI 扮演客戶的方式、定義報告的評分標準以及系統規則。</p><blockquote><p>僅限管理員存取。</p></blockquote><h2 id="介面結構" tabindex="-1">介面結構 <a class="header-anchor" href="#介面結構" aria-label="Permalink to &quot;介面結構&quot;">​</a></h2><p>管理頁面主要分為兩個區塊：</p><ul><li><strong>工具列與篩選器 (左側/上方)</strong>: <ul><li><strong>公司/部門下拉選單:</strong> 篩選出適用於特定組織的專屬提示詞（例如：台灣國泰人壽）。</li><li><strong>版本下拉選單:</strong> 選擇目前正在編輯的提示詞版本（例如：v1.0, v2.0 - 使用中）。</li></ul></li><li><strong>清單與編輯器</strong>: 顯示指定版本內的所有提示詞列表，以及用於編寫原始指令的大型文字編輯區。</li></ul><hr><h2 id="提示詞卡片細節" tabindex="-1">提示詞卡片細節 <a class="header-anchor" href="#提示詞卡片細節" aria-label="Permalink to &quot;提示詞卡片細節&quot;">​</a></h2><p>每張提示詞卡片會顯示以下資訊：</p><ul><li><strong>名稱</strong>: 系統內的唯一識別碼。</li><li><strong>分類 (Category)</strong>: 提示詞的類型（例如：System, Character, Judge, Auto-Suggestions）。</li><li><strong>描述</strong>: 簡要總結其功能。</li><li><strong>狀態</strong>: 標示該提示詞是否屬於「使用中 (Active)」的版本。</li></ul><p>點選卡片後，右側編輯器會提供充足的空間讓管理員直接輸入與維護指令。</p><hr><h2 id="變數系統" tabindex="-1">變數系統 <a class="header-anchor" href="#變數系統" aria-label="Permalink to &quot;變數系統&quot;">​</a></h2><p>在提示詞內容中，您可以使用大括號 <code>{...}</code> 包夾的動態變數，系統會在執行時自動填入實際資料： 例如：</p><ul><li><code>{question}</code>: 使用者最新的提問或對話。</li><li><code>{character_detail}</code>: 自動生成的客戶人物誌背景。</li><li><code>{conversation_history}</code>: 截至目前的對話歷史紀錄。</li><li><code>{stage_description}</code>: 當前適用的銷售階段描述。</li></ul><hr><h2 id="版本控制" tabindex="-1">版本控制 <a class="header-anchor" href="#版本控制" aria-label="Permalink to &quot;版本控制&quot;">​</a></h2><p>系統具備完整的版本管理，讓您可以安全地編輯及測試提示詞，不會影響正在進行的線上練習：</p><ul><li><strong>新增版本</strong>: 從目前的版本複製所有的提示詞，建立為一份新的草稿版。</li><li><strong>儲存變更</strong>: 所有的修改只會生效於您選定的版本草稿內。</li><li><strong>發布 (Publish)</strong>: 將草稿版本正式推送到生產環境，成為最新「使用中」的版本。注意：發布後，只有<em>全新</em>開啟的練習才會套用新版本。</li></ul>',21)])])}const g=t(l,[["render",i]]);export{u as __pageData,g as default};
